            WebkitBackgroundClip: 'text',
            backgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}
        >
          Portfolio Showcase
        </h2>
        <p className="text-gray-600 text-base md:text-lg max-w-2xl mx-auto">
