          position="static"
          elevation={0}
          sx={{
            bgcolor: "transparent",
            border: "1px solid rgba(34, 197, 94, 0.2)",
            borderRadius: "20px",
            position: "relative",
            overflow: "hidden",
            background: "linear-gradient(180deg, rgba(34, 197, 94, 0.05) 0%, rgba(74, 222, 128, 0.05) 100%)",
            backdropFilter: "blur(10px)",
          }}
          className="md:px-4"
        >
          <Tabs
            value={value}
            onChange={handleChange}
            textColor="secondary"
            indicatorColor="secondary"
